/* SERVITEC PRO V13.28.1 FIX FORMULARIOS ESTABLE - frontend estatico para Vercel */
const VERSION='SERVITEC PRO V13.28.1 FIX FORMULARIOS ESTABLE';
const STORE='servitec_pro_state_v1328';
const LEGACY=['servitec_pro_state_v1327','servitec_pro_state_v1317','servitec_v139'];
const $=s=>document.querySelector(s); const $$=s=>[...document.querySelectorAll(s)];
const uid=()=>Date.now().toString(36)+'_'+Math.random().toString(36).slice(2,7);
const esc=s=>String(s??'').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;');
const money=n=>'S/ '+(Number(n)||0).toFixed(2); const year=()=>new Date().getFullYear();
const MODES={GENERAL:'Actividades generales → varios equipos',PROPIAS:'Cada equipo con sus propias actividades',REPUESTOS:'Venta de repuestos / accesorios',MIXTO:'Servicio + repuestos'};
const seed={activeEmpresaId:'emp1',usuarios:[{id:'u_admin',nombre:'Administrador',usuario:'admin',clave:'admin123',rol:'ADMIN',estado:'ACTIVO'}],empresas:[{id:'emp1',nombre:'Nueva empresa',ruc:'',telefono:'',correo:'',direccion:'',representante:'',cargoRepresentante:'',logo:'',firma:'',moneda:'Soles (S/)',formaPago:'Crédito comercial',tiempoEjecucion:'10 días calendarios',lugarServicio:'En establecimiento del cliente',validez:'15 días calendario',garantia:'06 meses',observacionesCot:'Incluye mano de obra especializada.\nIncluye pruebas de funcionamiento.',contactoComercial:'',telefonoContacto:'',banco:'',cuenta:'',cci:'',prefijos:{cotizacion:'COT',acta:'ACT',informe:'INF',os:'OS'},correlativos:{cotizacion:1,acta:1,informe:1,os:1}}],clientes:[],cotizaciones:[],ejecuciones:[],inventario:[]};
let state=load(), tab='Dashboard', draft=null, msg='';
function clone(o){return JSON.parse(JSON.stringify(o||{}))}
function read(k){try{return JSON.parse(localStorage.getItem(k)||'null')}catch{return null}}
function score(s){return (s?.empresas?.length||0)*10+(s?.clientes?.length||0)*20+(s?.cotizaciones?.length||0)*50+(s?.ejecuciones?.length||0)*30}
function load(){let found=[read(STORE),...LEGACY.map(read)].filter(Boolean).sort((a,b)=>score(b)-score(a))[0];let s={...clone(seed),...(found||{})};normalize(s);localStorage.setItem(STORE,JSON.stringify(s));return s}
function save(){normalize(state);let raw=JSON.stringify(state);[STORE,'servitec_pro_state_v1317','servitec_v139'].forEach(k=>{try{localStorage.setItem(k,raw)}catch(e){console.warn('storage',k,e)}})}
function normalize(s=state){s.empresas=s.empresas?.length?s.empresas:clone(seed.empresas);s.clientes=s.clientes||[];s.cotizaciones=s.cotizaciones||[];s.ejecuciones=s.ejecuciones||[];s.inventario=s.inventario||[];if(!s.activeEmpresaId||!s.empresas.some(e=>e.id===s.activeEmpresaId))s.activeEmpresaId=s.empresas[0]?.id;for(const e of s.empresas){e.prefijos={cotizacion:'COT',acta:'ACT',informe:'INF',os:'OS',...(e.prefijos||{})};e.correlativos={cotizacion:Number(e.correlativoCotizacion||e.correlativos?.cotizacion||1),acta:Number(e.correlativoActa||e.correlativos?.acta||1),informe:Number(e.correlativoInforme||e.correlativos?.informe||1),os:Number(e.correlativoOS||e.correlativos?.os||1)};e.representante=e.representante||e.gerente||'';e.cargoRepresentante=e.cargoRepresentante||e.cargoGerente||'';e.moneda=e.moneda||'Soles (S/)';}for(const c of s.clientes){c.establecimientos=c.establecimientos||[];for(const es of c.establecimientos)es.areas=es.areas||[]}for(const q of s.cotizaciones){q.empresaId=q.empresaId||s.activeEmpresaId;q.acts=q.acts||q.actividades||[];q.equipos=q.equipos||[];q.repuestos=q.repuestos||[];applyTax(q)}}
function activeEmpresa(){return state.empresas.find(e=>e.id===state.activeEmpresaId)||state.empresas[0]||{}}
function empCot(){return state.cotizaciones.filter(q=>q.empresaId===activeEmpresa().id)}
function fmt(pref,n){return `${pref}-${year()}-${String(Number(n)||1).padStart(4,'0')}`}
function nextNum(tipo){let e=activeEmpresa(); return fmt(e.prefijos?.[tipo]||tipo.toUpperCase(), e.correlativos?.[tipo]||1)}
function consume(tipo){let e=activeEmpresa(); let n=nextNum(tipo); e.correlativos[tipo]=Number(e.correlativos[tipo]||1)+1; return n}
function applyTax(q){let sub=calcSub(q);q.subtotal=sub;q.igv=+(sub*.18).toFixed(2);q.total=+(sub*1.18).toFixed(2);return q}
function calcSub(q){let a=(q.acts||[]).reduce((s,x)=>s+(+x.cantidad||0)*(+x.precio||0),0);let r=(q.repuestos||[]).reduce((s,x)=>s+(+x.cantidad||0)*(+x.precio||0),0);if(q.config===MODES.PROPIAS)a=(q.equipos||[]).reduce((s,e)=>s+(e.acts||[]).reduce((z,x)=>z+(+x.cantidad||0)*(+x.precio||0),0),0);if(q.config===MODES.REPUESTOS)return r;return a+r}
function render(){normalize();document.title=VERSION;app.innerHTML=`<header class="top"><div><h1>${VERSION}</h1><small>Correlativos reales + PDF profesional + respaldo JSON + ejecución por actividad</small></div><button class="btn" onclick="alert('Sesión local cerrada')">Salir</button></header><nav class="nav">${['Dashboard','Empresas','Clientes','Cotizaciones','Ejecución','Actas','Informes','Inventario','Configuración','Usuarios'].map(x=>`<button class="${tab===x?'active':''}" onclick="tab='${x}';draft=null;render()">${x}</button>`).join('')}</nav><main>${views[tab]()}</main>`;bind()}
const back=()=>`<button class="btn primary" onclick="tab='Dashboard';draft=null;render()">← Atrás</button>`;
function table(h,rows){return `<div class="tableWrap"><table><thead><tr>${h.map(x=>`<th>${x}</th>`).join('')}</tr></thead><tbody>${rows.length?rows.map(r=>`<tr>${r.map(c=>`<td>${c??''}</td>`).join('')}</tr>`).join(''):`<tr><td colspan="${h.length}">Sin registros.</td></tr>`}</tbody></table></div>`}
const views={Dashboard(){return `<section class="wrap"><h2>Dashboard</h2><div class="grid"><div class="card"><b>Empresa activa</b><h3>${esc(activeEmpresa().nombre)}</h3></div><div class="card"><b>Clientes</b><h2>${state.clientes.filter(c=>(c.empresaId||activeEmpresa().id)===activeEmpresa().id).length}</h2></div><div class="card"><b>Cotizaciones</b><h2>${empCot().length}</h2></div><div class="card"><b>Inventario</b><h2>${state.inventario.filter(i=>(i.empresaId||activeEmpresa().id)===activeEmpresa().id).length}</h2></div></div><p class="notice">Base limpia: todos los módulos usan empresa activa, correlativos reales y almacenamiento único ${STORE}.</p>${msg?`<p class="notice">${esc(msg)}</p>`:''}</section>`},Empresas(){return viewEmpresas()},Clientes(){return viewClientes()},Cotizaciones(){return draft?quoteForm():quoteList()},Ejecución(){return viewExec()},Actas(){return viewDocs('ACTA DE CONFORMIDAD')},Informes(){return viewDocs('INFORME TÉCNICO')},Inventario(){return viewInv()},Configuración(){return viewConfig()},Usuarios(){return `<section class="wrap">${back()}<h2>Usuarios</h2>${table(['Nombre','Usuario','Rol','Estado'],state.usuarios.map(u=>[u.nombre,u.usuario,u.rol,u.estado]))}</section>`}};
function viewEmpresas(){let e=activeEmpresa();return `<section class="wrap">${back()}<h2>Empresas</h2><p class="notice"><b>Empresa activa:</b> ${esc(e.nombre)}</p><select id="empSel">${state.empresas.map(x=>`<option value="${x.id}" ${x.id===e.id?'selected':''}>${esc(x.nombre)}</option>`)}</select><div class="bar"><button class="btn" onclick="newEmpresa()">Nueva</button><button class="btn green" onclick="saveEmpresa()">Guardar cambios</button><button class="btn" onclick="state.activeEmpresaId=$('#empSel').value;save();render()">Activar empresa</button><button class="btn danger" onclick="delEmpresa()">Eliminar</button></div><div class="grid"><label class="field"><b>Razón social</b><input id="e_nombre" value="${esc(e.nombre)}"></label><label><b>RUC</b><input id="e_ruc" value="${esc(e.ruc)}"></label><label><b>Teléfono</b><input id="e_telefono" value="${esc(e.telefono)}"></label><label><b>Correo</b><input id="e_correo" value="${esc(e.correo)}"></label><label><b>Dirección</b><input id="e_direccion" value="${esc(e.direccion)}"></label><label><b>Representante</b><input id="e_representante" value="${esc(e.representante)}"></label><label><b>Cargo firmante</b><input id="e_cargo" value="${esc(e.cargoRepresentante)}"></label><label><b>Moneda</b><input id="e_moneda" value="${esc(e.moneda)}"></label></div><div class="grid2"><label><b>Logo empresa</b><input type="file" id="e_logo" accept="image/*"><small>${e.logo?'Logo cargado ✅':'Sin logo'}</small></label><label><b>Firma</b><input type="file" id="e_firma" accept="image/*"><small>${e.firma?'Firma cargada ✅':'Sin firma'}</small></label></div><h3>Condiciones comerciales y banco</h3><div class="grid"><input id="e_pago" placeholder="Forma de pago" value="${esc(e.formaPago)}"><input id="e_tiempo" placeholder="Tiempo de ejecución" value="${esc(e.tiempoEjecucion)}"><input id="e_lugar" placeholder="Lugar del servicio" value="${esc(e.lugarServicio)}"><input id="e_validez" placeholder="Validez" value="${esc(e.validez)}"><input id="e_garantia" placeholder="Garantía" value="${esc(e.garantia)}"><input id="e_contacto" placeholder="Contacto comercial" value="${esc(e.contactoComercial)}"><input id="e_telcontacto" placeholder="Teléfono contacto" value="${esc(e.telefonoContacto)}"><input id="e_banco" placeholder="Banco" value="${esc(e.banco)}"><input id="e_cuenta" placeholder="Cuenta" value="${esc(e.cuenta)}"><input id="e_cci" placeholder="CCI" value="${esc(e.cci)}"></div><textarea id="e_obs" placeholder="Observaciones comerciales">${esc(e.observacionesCot)}</textarea><h3>Correlativos por empresa</h3><p class="notice">Estos campos son el <b>próximo número a emitir</b>. Si colocas 206, la siguiente cotización será COT-${year()}-0206.</p>${table(['Documento','Prefijo','Próximo número','Vista previa'],[['cotizacion','Cotización'],['acta','Acta'],['informe','Informe'],['os','Orden servicio']].map(([k,l])=>[l,`<input id="pref_${k}" value="${esc(e.prefijos[k])}">`,`<input type="number" id="corr_${k}" value="${Number(e.correlativos[k]||1)}">`,`<b>${fmt(e.prefijos[k],e.correlativos[k])}</b>`]))}</section>`}
async function file64(id){let f=$(id)?.files?.[0]; if(!f)return null; return await new Promise(res=>{let r=new FileReader();r.onload=()=>res(r.result);r.readAsDataURL(f)})}
async function saveEmpresa(){let e=activeEmpresa();Object.assign(e,{nombre:$('#e_nombre').value,ruc:$('#e_ruc').value,telefono:$('#e_telefono').value,correo:$('#e_correo').value,direccion:$('#e_direccion').value,representante:$('#e_representante').value,cargoRepresentante:$('#e_cargo').value,moneda:$('#e_moneda').value,formaPago:$('#e_pago').value,tiempoEjecucion:$('#e_tiempo').value,lugarServicio:$('#e_lugar').value,validez:$('#e_validez').value,garantia:$('#e_garantia').value,contactoComercial:$('#e_contacto').value,telefonoContacto:$('#e_telcontacto').value,banco:$('#e_banco').value,cuenta:$('#e_cuenta').value,cci:$('#e_cci').value,observacionesCot:$('#e_obs').value});for(const k of ['cotizacion','acta','informe','os']){e.prefijos[k]=$('#pref_'+k).value||k.toUpperCase();e.correlativos[k]=Number($('#corr_'+k).value)||1}let logo=await file64('#e_logo'),firma=await file64('#e_firma'); if(logo)e.logo=logo;if(firma)e.firma=firma;save();msg='Empresa guardada.';render()}
function newEmpresa(){let e=clone(seed.empresas[0]);e.id=uid();e.nombre='Nueva empresa';state.empresas.push(e);state.activeEmpresaId=e.id;save();render()}function delEmpresa(){if(state.empresas.length<=1)return alert('Debe existir al menos una empresa.');if(confirm('¿Eliminar empresa activa?')){let id=activeEmpresa().id;state.empresas=state.empresas.filter(e=>e.id!==id);state.activeEmpresaId=state.empresas[0].id;save();render()}}
function viewClientes(){let cs=state.clientes.filter(c=>(c.empresaId||activeEmpresa().id)===activeEmpresa().id);let c=cs[0];return `<section class="wrap">${back()}<h2>Clientes</h2><div class="grid"><input id="cli_nom" placeholder="Nombre / razón social"><input id="cli_ruc" placeholder="RUC"><input id="cli_tel" placeholder="Teléfono"><input id="cli_cor" placeholder="Correo"><input id="cli_dir" placeholder="Dirección"><input id="cli_resp" placeholder="Responsable"></div><div class="bar"><button class="btn green" onclick="addCliente()">Guardar cliente nuevo</button></div>${table(['Cliente','RUC','Responsable','Acciones'],cs.map(x=>[x.nombre,x.ruc,x.responsable,`<button class="btn" onclick="editCliente('${x.id}')">Editar</button><button class="btn danger" onclick="delCliente('${x.id}')">Eliminar</button>`]))}${c?`<div class="card"><h3>Establecimientos de ${esc(c.nombre)}</h3><div class="grid2"><input id="est_nom" placeholder="Nuevo establecimiento"><input id="est_dir" placeholder="Dirección establecimiento"></div><button class="btn green" onclick="addEst('${c.id}')">Agregar establecimiento</button>${(c.establecimientos||[]).map(e=>`<div class="card"><b>${esc(e.nombre)}</b><br><small>${esc(e.direccion)}</small><div class="grid2"><input id="area_${e.id}" placeholder="Área usuaria"><button class="btn" onclick="addArea('${c.id}','${e.id}')">Agregar área</button></div><ul>${(e.areas||[]).map(a=>`<li>${esc(a.nombre)}</li>`).join('')}</ul></div>`).join('')}</div>`:''}</section>`}
function addCliente(){state.clientes.push({id:uid(),empresaId:activeEmpresa().id,nombre:$('#cli_nom').value,ruc:$('#cli_ruc').value,telefono:$('#cli_tel').value,correo:$('#cli_cor').value,direccion:$('#cli_dir').value,responsable:$('#cli_resp').value,establecimientos:[]});save();render()}function editCliente(id){let c=state.clientes.find(x=>x.id===id);let n=prompt('Nombre cliente',c.nombre);if(n!==null)c.nombre=n;save();render()}function delCliente(id){if(confirm('¿Eliminar cliente?')){state.clientes=state.clientes.filter(c=>c.id!==id);save();render()}}function addEst(cid){let c=state.clientes.find(x=>x.id===cid);c.establecimientos.push({id:uid(),nombre:$('#est_nom').value,direccion:$('#est_dir').value,areas:[]});save();render()}function addArea(cid,eid){let c=state.clientes.find(x=>x.id===cid),e=c.establecimientos.find(x=>x.id===eid);e.areas.push({id:uid(),nombre:$('#area_'+eid).value});save();render()}
function newDraft(){let c=state.clientes.find(x=>(x.empresaId||activeEmpresa().id)===activeEmpresa().id)||{}, es=c.establecimientos?.[0]||{}, ar=es.areas?.[0]||{};return {id:uid(),empresaId:activeEmpresa().id,numero:nextNum('cotizacion'),clienteId:c.id||'',clienteNombre:c.nombre||'',estId:es.id||'',establecimientoNombre:es.nombre||'',areaId:ar.id||'',areaNombre:ar.nombre||'',tipo:'Servicio',config:MODES.GENERAL,acts:[],equipos:[],repuestos:[],estado:'Cotización',fecha:new Date().toISOString(),subtotal:0,igv:0,total:0}}
function quoteList(){let qs=empCot();return `<section class="wrap">${back()}<h2>Cotizaciones</h2><p class="notice"><b>Empresa activa:</b> ${esc(activeEmpresa().nombre)}</p><button class="btn green" onclick="draft=newDraft();render()">Nueva</button>${table(['N°','Cliente','Configuración','Estado','Total','Acciones'],qs.map(q=>[q.numero,q.clienteNombre,q.config,q.estado,money(q.total),`<button class="btn" onclick="draft=clone(state.cotizaciones.find(x=>x.id==='${q.id}'));render()">Editar</button> <button class="btn green" onclick="printQuote('${q.id}')">PDF</button> <button class="btn" onclick="tab='Ejecución';localStorage.setItem('exec_q', '${q.id}');render()">Ejecutar</button> <button class="btn danger" onclick="delQuote('${q.id}')">Eliminar</button>`]))}</section>`}
function quoteForm(){let clients=state.clientes.filter(c=>(c.empresaId||activeEmpresa().id)===activeEmpresa().id);let c=clients.find(x=>x.id===draft.clienteId)||clients[0]||{}, ests=c.establecimientos||[], es=ests.find(x=>x.id===draft.estId)||ests[0]||{}, areas=es.areas||[];applyTax(draft);return `<section class="wrap">${back()}<h2>${draft.id&&state.cotizaciones.some(q=>q.id===draft.id)?'Editar':'Nueva'} cotización</h2><div class="grid"><select id="q_cli">${clients.map(x=>`<option value="${x.id}" ${x.id===draft.clienteId?'selected':''}>${esc(x.nombre)}</option>`)}</select><select id="q_est">${ests.map(x=>`<option value="${x.id}" ${x.id===draft.estId?'selected':''}>${esc(x.nombre)}</option>`)}</select><select id="q_area">${areas.map(x=>`<option value="${x.id}" ${x.id===draft.areaId?'selected':''}>${esc(x.nombre)}</option>`)}</select><select id="q_config">${Object.values(MODES).map(x=>`<option ${x===draft.config?'selected':''}>${x}</option>`)}</select></div><div class="bar"><span class="pill">${esc(draft.numero)}</span><b class="total">Total con IGV: ${money(draft.total)}</b></div>${quoteItems()}<div class="bar"><button class="btn green" onclick="saveQuote()">Guardar y volver a lista</button><button class="btn" onclick="draft=null;render()">Cancelar</button></div></section>`}
function quoteItems(){let html=`<h3>Actividades del servicio</h3><button class="btn green" onclick="draft.acts.push({id:uid(),descripcion:'',cantidad:1,precio:0});render()">+ Actividad</button>${itemTable(draft.acts,'act')}<h3>Repuestos / accesorios</h3><button class="btn green" onclick="draft.repuestos.push({id:uid(),codigo:'',descripcion:'',cantidad:1,precio:0});render()">+ Repuesto</button>${itemTable(draft.repuestos,'rep')}<h3>Equipos incluidos</h3><button class="btn green" onclick="draft.equipos.push({id:uid(),nombre:'',cantidad:1,marca:'',modelo:'',serie:''});render()">+ Equipo</button>${equipTable()}`;return html}
function itemTable(arr,type){return `<div class="tableWrap"><table><thead><tr>${type==='rep'?'<th>Código</th>':''}<th>Descripción</th><th>Cant.</th><th>Precio</th><th>Subtotal</th></tr></thead><tbody>${arr.map(x=>`<tr>${type==='rep'?`<td><input data-id="${x.id}" data-type="${type}" data-k="codigo" value="${esc(x.codigo)}"></td>`:''}<td><textarea data-id="${x.id}" data-type="${type}" data-k="descripcion">${esc(x.descripcion)}</textarea></td><td><input type="number" data-id="${x.id}" data-type="${type}" data-k="cantidad" value="${x.cantidad}"></td><td><input type="number" data-id="${x.id}" data-type="${type}" data-k="precio" value="${x.precio}"></td><td>${money((+x.cantidad||0)*(+x.precio||0))}</td></tr>`).join('')}</tbody></table></div>`}
function equipTable(){return `<div class="tableWrap"><table><thead><tr><th>Tipo / Equipo</th><th>Cant.</th><th>Marca</th><th>Modelo</th><th>Serie</th></tr></thead><tbody>${draft.equipos.map(e=>`<tr><td><input data-eqid="${e.id}" data-k="nombre" value="${esc(e.nombre)}"></td><td><input type="number" data-eqid="${e.id}" data-k="cantidad" value="${e.cantidad||1}"></td><td><input data-eqid="${e.id}" data-k="marca" value="${esc(e.marca)}"></td><td><input data-eqid="${e.id}" data-k="modelo" value="${esc(e.modelo)}"></td><td><input data-eqid="${e.id}" data-k="serie" value="${esc(e.serie)}"></td></tr>`).join('')}</tbody></table></div>`}
function saveQuote(){let c=state.clientes.find(x=>x.id===$('#q_cli').value)||{}, es=(c.establecimientos||[]).find(x=>x.id===$('#q_est').value)||{}, ar=(es.areas||[]).find(x=>x.id===$('#q_area').value)||{};Object.assign(draft,{empresaId:activeEmpresa().id,clienteId:c.id,clienteNombre:c.nombre,estId:es.id,establecimientoNombre:es.nombre,areaId:ar.id,areaNombre:ar.nombre,config:$('#q_config').value});applyTax(draft);let i=state.cotizaciones.findIndex(q=>q.id===draft.id);if(i>=0){state.cotizaciones[i]=clone(draft)}else{draft.numero=nextNum('cotizacion');consume('cotizacion');state.cotizaciones.push(clone(draft))}save();draft=null;render()}function delQuote(id){if(confirm('¿Eliminar cotización?')){state.cotizaciones=state.cotizaciones.filter(q=>q.id!==id);state.ejecuciones=state.ejecuciones.filter(e=>e.cotizacionId!==id);save();render()}}
function rows(q){let r=[...(q.acts||[]).map((x,i)=>({n:i+1,desc:x.descripcion,cant:x.cantidad,precio:x.precio,sub:(+x.cantidad||0)*(+x.precio||0)})),...(q.repuestos||[]).map((x,i)=>({n:(q.acts||[]).length+i+1,desc:(x.codigo?x.codigo+' - ':'')+x.descripcion,cant:x.cantidad,precio:x.precio,sub:(+x.cantidad||0)*(+x.precio||0)}))];return r}
function printQuote(id){let q=state.cotizaciones.find(x=>x.id===id), e=state.empresas.find(x=>x.id===q.empresaId)||activeEmpresa();let w=open('','_blank');if(!w)return alert('Permite ventanas emergentes para generar PDF.');w.document.write(docCot(q,e));w.document.close();setTimeout(()=>w.print(),300)}
function docCot(q,e){let rs=rows(q);return `<!doctype html><html><head><title>${esc(q.numero)}</title><link rel="stylesheet" href="styles.css?v=13.28.1"></head><body class="docprint onepage"><div class="wm">${e.logo?`<img src="${e.logo}">`:''}</div><div class="head"><div>${e.logo?`<img class="logo" src="${e.logo}">`:''}<h2>${esc(e.nombre)}</h2><p><b>RUC:</b> ${esc(e.ruc)}<br><b>Dirección:</b> ${esc(e.direccion)}<br><b>Tel:</b> ${esc(e.telefono)} · ${esc(e.correo)}</p></div><div><h2>${esc(q.numero)}</h2><p><b>Fecha:</b> ${new Date(q.fecha).toLocaleDateString()}<br><b>Moneda:</b> ${esc(e.moneda)}</p></div></div><h1>COTIZACIÓN</h1><p><b>Cliente:</b> ${esc(q.clienteNombre)}<br><b>Establecimiento:</b> ${esc(q.establecimientoNombre)} · <b>Área:</b> ${esc(q.areaNombre||'-')}</p>${table(['Ítem','Descripción','Cant.','P. Unit.','Subtotal'],rs.map(r=>[r.n,esc(r.desc),r.cant,money(r.precio),money(r.sub)]))}<p><b>Equipos incluidos:</b> ${(q.equipos||[]).map(x=>`${esc(x.nombre)} ${esc(x.marca||'')} ${esc(x.modelo||'')} ${esc(x.serie||'')}`).join('; ')||'-'}</p><div style="width:260px;margin-left:auto">${table(['Concepto','Monto'],[['Subtotal',money(q.subtotal)],['IGV 18%',money(q.igv)],['TOTAL',`<b>${money(q.total)}</b>`]])}</div><div class="grid2"><div><b>Condiciones</b><p>Forma de pago: ${esc(e.formaPago)}<br>Tiempo de ejecución: ${esc(e.tiempoEjecucion)}<br>Lugar: ${esc(e.lugarServicio)}<br>Validez: ${esc(e.validez)}<br>Garantía: ${esc(e.garantia)}</p><p>${esc(e.observacionesCot).replaceAll('\n','<br>')}</p></div><div><b>Datos bancarios</b><p>Banco: ${esc(e.banco)}<br>Cuenta: ${esc(e.cuenta)}<br>CCI: ${esc(e.cci)}<br>Contacto: ${esc(e.contactoComercial)} ${esc(e.telefonoContacto)}</p></div></div><div class="firmas"><div class="firma">${e.firma?`<img src="${e.firma}">`:''}<b>${esc(e.representante)}</b><br>${esc(e.cargoRepresentante)}<br>${esc(e.nombre)}</div></div></body></html>`}
function ensureExec(q){let ex=state.ejecuciones.find(e=>e.cotizacionId===q.id);if(!ex){ex={id:uid(),empresaId:q.empresaId,cotizacionId:q.id,os:'',siaf:'',equipos:(q.equipos.length?q.equipos:[{id:uid(),nombre:'Servicio general',cantidad:1}]).map(eq=>({id:eq.id,nombre:eq.nombre,marca:eq.marca,modelo:eq.modelo,serie:eq.serie,actividades:(q.acts.length?q.acts:[{id:uid(),descripcion:'Servicio'}]).map(a=>({id:a.id,descripcion:a.descripcion,estado:'Pendiente',comentario:'',recomendacion:'',antes:'',durante:'',despues:''}))}))};state.ejecuciones.push(ex);save()}return ex}
function viewExec(){let qs=empCot();if(!qs.length)return `<section class="wrap">${back()}<h2>Ejecución</h2><p class="notice">No hay cotizaciones registradas.</p></section>`;let id=localStorage.getItem('exec_q')||qs[0].id,q=qs.find(x=>x.id===id)||qs[0],ex=ensureExec(q);return `<section class="wrap">${back()}<h2>Ejecución por actividad</h2><select onchange="localStorage.setItem('exec_q',this.value);render()">${qs.map(x=>`<option value="${x.id}" ${x.id===q.id?'selected':''}>${x.numero} - ${x.clienteNombre}</option>`)}</select><div class="grid2"><input id="ex_os" placeholder="OS/OC" value="${esc(ex.os)}"><input id="ex_siaf" placeholder="SIAF" value="${esc(ex.siaf)}"></div><button class="btn green" onclick="saveExec('${ex.id}')">Guardar ejecución</button>${ex.equipos.map(eq=>`<div class="card"><h3>${esc(eq.nombre)}</h3>${eq.actividades.map(a=>`<div class="card"><b>${esc(a.descripcion)}</b><div class="grid3"><select data-ex="${ex.id}" data-eq="${eq.id}" data-ac="${a.id}" data-k="estado"><option ${a.estado==='Pendiente'?'selected':''}>Pendiente</option><option ${a.estado==='Terminado'?'selected':''}>Terminado</option><option ${a.estado==='Observado'?'selected':''}>Observado</option></select><textarea data-ex="${ex.id}" data-eq="${eq.id}" data-ac="${a.id}" data-k="comentario" placeholder="Comentario / observación">${esc(a.comentario)}</textarea><textarea data-ex="${ex.id}" data-eq="${eq.id}" data-ac="${a.id}" data-k="recomendacion" placeholder="Recomendación">${esc(a.recomendacion)}</textarea></div><div class="grid3"><label>Antes<input type="file" accept="image/*" data-img="antes" data-ex="${ex.id}" data-eq="${eq.id}" data-ac="${a.id}">${a.antes?'<span class="ok"> cargado ✅</span>':''}</label><label>Durante<input type="file" accept="image/*" data-img="durante" data-ex="${ex.id}" data-eq="${eq.id}" data-ac="${a.id}">${a.durante?'<span class="ok"> cargado ✅</span>':''}</label><label>Después<input type="file" accept="image/*" data-img="despues" data-ex="${ex.id}" data-eq="${eq.id}" data-ac="${a.id}">${a.despues?'<span class="ok"> cargado ✅</span>':''}</label></div></div>`).join('')}</div>`).join('')}</section>`}
async function saveExec(id){let ex=state.ejecuciones.find(x=>x.id===id);ex.os=$('#ex_os').value;ex.siaf=$('#ex_siaf').value;for(const el of $$('[data-ex]')){let eq=ex.equipos.find(x=>x.id===el.dataset.eq),a=eq?.actividades.find(x=>x.id===el.dataset.ac);if(!a)continue;if(el.dataset.k)a[el.dataset.k]=el.value;if(el.dataset.img&&el.files?.[0])a[el.dataset.img]=await new Promise(res=>{let r=new FileReader();r.onload=()=>res(r.result);r.readAsDataURL(el.files[0])})}let q=state.cotizaciones.find(q=>q.id===ex.cotizacionId);if(q){q.ordenNumero=ex.os;q.siaf=ex.siaf;q.estado=ex.os&&ex.siaf?'En ejecución':q.estado}save();msg='Ejecución guardada por actividad.';render()}
function viewDocs(tipo){let qs=empCot().filter(q=>state.ejecuciones.some(e=>e.cotizacionId===q.id));return `<section class="wrap">${back()}<h2>${tipo}</h2>${table(['Cotización','Cliente','Acción'],qs.map(q=>[q.numero,q.clienteNombre,`<button class="btn green" onclick="printDoc('${q.id}','${tipo}')">Generar PDF</button>`]))}</section>`}
function printDoc(id,tipo){let q=state.cotizaciones.find(q=>q.id===id),e=state.empresas.find(x=>x.id===q.empresaId)||activeEmpresa(),ex=state.ejecuciones.find(x=>x.cotizacionId===id)||ensureExec(q);let w=open('','_blank');w.document.write(tipo.includes('ACTA')?docActa(q,e,ex):docInforme(q,e,ex));w.document.close();setTimeout(()=>w.print(),300)}
function actRows(ex){let out=[];for(const eq of ex.equipos)for(const a of eq.actividades)out.push([eq.nombre,a.descripcion,a.estado,a.comentario]);return out}
function docActa(q,e,ex){return `<!doctype html><html><head><title>ACTA ${q.numero}</title><link rel="stylesheet" href="styles.css?v=13.28.1"></head><body class="docprint"><div class="wm">${e.logo?`<img src="${e.logo}">`:''}</div><div class="head"><div>${e.logo?`<img class="logo" src="${e.logo}">`:''}<b>${esc(e.nombre)}</b><br>RUC ${esc(e.ruc)}</div><div><b>ACTA DE CONFORMIDAD</b><br>${esc(q.numero)}<br>OS/OC: ${esc(ex.os)} · SIAF: ${esc(ex.siaf)}</div></div><h1>ACTA DE CONFORMIDAD DE SERVICIO</h1><p>El área usuaria deja constancia de la ejecución de las actividades correspondientes al servicio indicado.</p><p><b>Cliente:</b> ${esc(q.clienteNombre)}<br><b>Establecimiento:</b> ${esc(q.establecimientoNombre)}<br><b>Área:</b> ${esc(q.areaNombre)}</p>${table(['Equipo','Actividad','Estado','Observación'],actRows(ex))}<div class="firmas"><div class="firma">Responsable área usuaria</div><div class="firma">Técnico responsable</div><div class="firma">${e.firma?`<img src="${e.firma}">`:''}${esc(e.representante)}<br>Empresa contratista</div></div></body></html>`}
function docInforme(q,e,ex){let rows=actRows(ex);return `<!doctype html><html><head><title>INFORME ${q.numero}</title><link rel="stylesheet" href="styles.css?v=13.28.1"></head><body class="docprint"><div class="wm">${e.logo?`<img src="${e.logo}">`:''}</div><div class="head"><div>${e.logo?`<img class="logo" src="${e.logo}">`:''}<b>${esc(e.nombre)}</b><br>RUC ${esc(e.ruc)}</div><div><b>INFORME TÉCNICO</b><br>${esc(q.numero)}</div></div><h1>INFORME TÉCNICO</h1><p><b>Dirigido a:</b> ${esc(q.clienteNombre)}<br><b>Asunto:</b> Informe técnico del servicio ejecutado según ${esc(q.numero)}.</p><h3>1. Antecedentes</h3><p>Se programó la intervención técnica en ${esc(q.establecimientoNombre)} para la atención del servicio contratado.</p><h3>2. Datos del servicio</h3><p><b>OS/OC:</b> ${esc(ex.os)} · <b>SIAF:</b> ${esc(ex.siaf)} · <b>Área:</b> ${esc(q.areaNombre)}</p><h3>3. Actividades realizadas</h3>${table(['Equipo','Actividad','Estado','Comentario técnico'],rows)}<h3>4. Hallazgos y observaciones</h3><p>${rows.map(r=>esc(r[3])).filter(Boolean).join('<br>')||'Durante la intervención no se registraron observaciones críticas adicionales.'}</p><h3>5. Conclusiones</h3><p>Las actividades fueron ejecutadas conforme al alcance contratado, quedando el servicio registrado para conformidad del área usuaria.</p><h3>6. Recomendaciones</h3><p>${ex.equipos.flatMap(eq=>eq.actividades.map(a=>a.recomendacion).filter(Boolean)).map(esc).join('<br>')||'Mantener programación periódica de mantenimiento y operación responsable del equipamiento.'}</p><div class="firmas"><div class="firma">Técnico responsable</div><div class="firma">${e.firma?`<img src="${e.firma}">`:''}${esc(e.representante)}<br>${esc(e.cargoRepresentante)}</div></div></body></html>`}
function viewInv(){return `<section class="wrap">${back()}<h2>Inventario</h2><div class="grid"><select id="i_tipo"><option>Equipo</option><option>Repuesto</option><option>Accesorio</option></select><input id="i_cod" placeholder="Código"><input id="i_desc" placeholder="Descripción"><input id="i_stock" type="number" placeholder="Stock"></div><button class="btn green" onclick="state.inventario.push({id:uid(),empresaId:activeEmpresa().id,tipo:$('#i_tipo').value,codigo:$('#i_cod').value,descripcion:$('#i_desc').value,stock:$('#i_stock').value});save();render()">Agregar</button>${table(['Tipo','Código','Descripción','Stock'],state.inventario.filter(i=>i.empresaId===activeEmpresa().id).map(i=>[i.tipo,i.codigo,i.descripcion,i.stock]))}</section>`}
function viewConfig(){return `<section class="wrap">${back()}<h2>Configuración y respaldo</h2><p class="notice">El respaldo evita volver a ingresar datos ante cualquier cambio de versión.</p><div class="bar"><button class="btn green" onclick="exportBackup()">Exportar respaldo JSON</button><label class="btn">Importar respaldo JSON<input class="hidden" type="file" accept="application/json,.json,.txt" onchange="importBackup(this)"></label><button class="btn danger" onclick="if(confirm('¿Limpiar solo operación? Conserva empresas.')){state.clientes=[];state.cotizaciones=[];state.ejecuciones=[];state.inventario=[];save();render()}">Limpiar base operativa</button></div><p><b>Clave principal:</b> ${STORE}</p></section>`}
function exportBackup(){download(`RESPALDO_SERVITEC_${new Date().toISOString().slice(0,10)}.json`,JSON.stringify(state,null,2),'application/json')}function importBackup(input){let f=input.files[0];if(!f)return;let r=new FileReader();r.onload=()=>{try{state=JSON.parse(r.result);normalize();save();msg='Respaldo importado correctamente.';render()}catch(e){alert('Archivo inválido')}};r.readAsText(f)}function download(n,c,t){let a=document.createElement('a');a.href=URL.createObjectURL(new Blob([c],{type:t}));a.download=n;a.click()}
function updateDraftTotalBox(){
  if(!draft) return;
  applyTax(draft);
  const t=document.querySelector('.total');
  if(t) t.textContent='Total con IGV: '+money(draft.total);
}
function bind(){
  if(window.__servitecBound) return;
  window.__servitecBound=true;
  document.addEventListener('input',ev=>{
    let el=ev.target;
    if(!draft) return;
    if(el.dataset.type){
      let arr=el.dataset.type==='act'?draft.acts:draft.repuestos;
      let it=arr.find(x=>x.id===el.dataset.id);
      if(it){it[el.dataset.k]=el.value;updateDraftTotalBox()}
    }else if(el.dataset.eqid){
      let it=draft.equipos.find(x=>x.id===el.dataset.eqid);
      if(it){it[el.dataset.k]=el.value}
    }
  });
  document.addEventListener('change',ev=>{
    let el=ev.target;
    if(!draft) return;
    if(el.id==='q_cli'){let c=state.clientes.find(x=>x.id===el.value)||{};let es=c.establecimientos?.[0]||{};let ar=es.areas?.[0]||{};Object.assign(draft,{clienteId:c.id||'',clienteNombre:c.nombre||'',estId:es.id||'',establecimientoNombre:es.nombre||'',areaId:ar.id||'',areaNombre:ar.nombre||''});render()}
    if(el.id==='q_est'){let c=state.clientes.find(x=>x.id===draft.clienteId)||{};let es=(c.establecimientos||[]).find(x=>x.id===el.value)||{};let ar=es.areas?.[0]||{};Object.assign(draft,{estId:es.id||'',establecimientoNombre:es.nombre||'',areaId:ar.id||'',areaNombre:ar.nombre||''});render()}
    if(el.id==='q_area'){let c=state.clientes.find(x=>x.id===draft.clienteId)||{};let es=(c.establecimientos||[]).find(x=>x.id===draft.estId)||{};let ar=(es.areas||[]).find(x=>x.id===el.value)||{};Object.assign(draft,{areaId:ar.id||'',areaNombre:ar.nombre||''})}
    if(el.id==='q_config'){draft.config=el.value;render()}
    if(el.dataset.type||el.dataset.eqid){save()}
  });
  document.addEventListener('blur',ev=>{if(draft&&(ev.target.dataset.type||ev.target.dataset.eqid)){save()}},true);
}
window.addEventListener('beforeunload',save);bind();render();
